def procesar_pedido(producto, cantidad, usuario):
    if usuario:
        if usuario.activo:
            if producto:
                if producto.stock &gt;= cantidad:
                    if usuario.saldo &gt;= producto.precio * cantidad:
                        print("Pedido procesado")
