Errores comunes

❌ Sin caso base: recursión infinita


PYTHON

# ❌ Nunca para — RecursionError
def sin_fin(n):
    print(n)
    return sin_fin(n - 1)  # No hay condición de parada

# ✅ Siempre incluye un caso base
def con_fin(n):
    if n &lt;= 0:
        return "Listo"
    print(n)
    return con_fin(n - 1)



❌ Caso base que nunca se alcanza


PYTHON

# ❌ El caso base nunca se alcanza porque n siempre aumenta
def mal_contador(n):
    if n == 0:  # Nunca llega a 0 si empieza en 5
        return "Listo"
    return mal_contador(n + 1)  # ¡Se aleja del caso base!

# ✅ El caso recursivo debe ACERCARSE al caso base
def buen_contador(n):
    if n &lt;= 0:
        return "Listo"
    return buen_contador(n - 1)  # Se acerca a 0



❌ No usar el return del caso recursivo


PYTHON

# ❌ Olvida retornar el resultado de la llamada recursiva
def factorial_roto(n):
    if n &lt;= 1:
        return 1
    n * factorial_roto(n - 1)  # ❌ Falta 'return' — devuelve None

# ✅ Siempre retorna el resultado
def factorial_correcto(n):
    if n &lt;= 1:
        return 1
    return n * factorial_correcto(n - 1)

⚠️ La trampa del set vacío


PYTHON

# ❌ Esto NO es un set, es un diccionario
dato = {}
print(type(dato))  # &lt;class 'dict'&gt;

# ✅ Esta es la forma correcta
conjunto = set()
print(type(conjunto))  # &lt;class 'set'&gt;


Explicit is better than implicit. set() deja claro que quieres un conjunto. {} es ambiguo — Python lo interpreta como diccionario.

