"""Módulo de cálculos estadísticos."""


def media(valores):
    """Calcula el promedio de una lista de números."""
    if not valores:
        return 0.0
    return sum(valores) / len(valores)


def mediana(valores):
    """Calcula el valor central de una lista ordenada."""
    if not valores:
        return 0.0
    ordenados = sorted(valores)
    n = len(ordenados)
    medio = n // 2
    if n % 2 == 0:
        return (ordenados[medio - 1] + ordenados[medio]) / 2
    return ordenados[medio]


def moda(valores):
    """Retorna el valor más frecuente."""
    if not valores:
        return None
    frecuencias = {}
    for v in valores:
        frecuencias[v] = frecuencias.get(v, 0) + 1
    return max(frecuencias, key=frecuencias.get)


def desviacion_estandar(valores):
    """Calcula la desviación estándar de la muestra."""
    if len(valores) &lt; 2:
        return 0.0
    promedio = media(valores)
    varianza = sum((x - promedio) ** 2 for x in valores) / (len(valores) - 1)
    return varianza ** 0.5


def minimo(valores):
    """Retorna el valor mínimo."""
    return min(valores) if valores else 0.0


def maximo(valores):
    """Retorna el valor máximo."""
    return max(valores) if valores else 0.0


def resumen_numerico(valores, etiqueta="dato"):
    """Genera un resumen estadístico completo."""
    return {
        "etiqueta": etiqueta,
        "cantidad": len(valores),
        "media": media(valores),
        "mediana": mediana(valores),
        "moda": moda(valores),
        "minimo": minimo(valores),
        "maximo": maximo(valores),
        "desviacion": desviacion_estandar(valores),
        "rango": maximo(valores) - minimo(valores),
    }

📝 Funciones de referencia


PYTHON

# El corazón del cifrado:
def apply_shift(texto, desplazamiento):
    resultado = []
    for caracter in texto:
        if caracter.isalpha():
            base = ord("A") if caracter.isupper() else ord("a")
            # Convertir a 0-25, desplazar, envolver, convertir de vuelta
            numero = (ord(caracter) - base + desplazamiento) % 26
            resultado.append(chr(base + numero))
        else:
            resultado.append(caracter)
    return "".join(resultado)


# Descifrar = cifrar con desplazamiento inverso:
def descifrar(texto_cifrado, desplazamiento):
    return apply_shift(texto_cifrado, -desplazamiento)


# Verificación rápida:
assert descifrar(cifrar("Hola Mundo", 5), 5) == "Hola Mundo"


There should be one obvious way to do it. apply_shift es la única función que necesita existir. cifrar y descifrar son aliases con nombres más descriptivos.

